// Parse incoming LinkedIn profiles for Apollo enrichment + sequence
const input = $input.item.json;
let data = input.body || input;
if (typeof data === 'string') data = JSON.parse(data);

const profiles = data.profiles || [];
const apolloApiKey = data.apollo_api_key || '';
const emailAccountId = data.email_account_id || '';
const sequenceMap = data.sequence_map || {};

console.log(`Processing ${profiles.length} LinkedIn profiles for Apollo enrichment`);

const items = profiles.map(profile => ({
  json: {
    // Profile data from scraped_profiles
    profile_id: profile.id,
    full_name: profile.full_name,
    first_name: profile.first_name || (profile.full_name || '').split(' ')[0] || '',
    last_name: profile.last_name || (profile.full_name || '').split(' ').slice(1).join(' ') || '',
    headline: profile.headline || '',
    company: profile.company || '',
    linkedin_url: profile.linkedin_url || '',
    location: profile.location || '',
    lead_score: profile.lead_score || 0,
    total_interactions: profile.total_interactions || 0,
    // Apollo config
    apollo_api_key: apolloApiKey,
    email_account_id: emailAccountId,
    sequence_map: sequenceMap
  }
}));

return items;

// Merge enriched Apollo data with original profile
const response = $json;
const profile = $('Parse LinkedIn Profiles').item.json;

let enrichedData = {};
let enrichmentSuccess = false;

try {
  const body = response.body || response;
  const person = body.person || body;

  if (person && person.email) {
    enrichmentSuccess = true;
    enrichedData = {
      email: person.email || '',
      title: person.title || profile.headline || '',
      company_name: person.organization?.name || person.organization_name || profile.company || '',
      industry: person.organization?.industry || '',
      num_employees: person.organization?.estimated_num_employees || '',
      city: person.city || '',
      state: person.state || '',
      country: person.country || '',
      website: person.organization?.website_url || '',
      technologies: (person.organization?.current_technologies || []).map(t => t.name || t).join(', '),
      keywords: (person.organization?.keywords || []).join(', '),
      seniority: person.seniority || '',
      departments: (person.departments || []).join(', '),
      apollo_person_id: person.id || ''
    };
    console.log(`Enriched ${profile.full_name}: ${enrichedData.email} at ${enrichedData.company_name}`);
  } else {
    console.log(`No email found for ${profile.full_name} via Apollo enrichment`);
    enrichedData = {
      email: '',
      title: profile.headline || '',
      company_name: profile.company || '',
      industry: '',
      num_employees: '',
      city: '',
      state: '',
      country: '',
      website: '',
      technologies: '',
      keywords: '',
      seniority: '',
      departments: '',
      apollo_person_id: ''
    };
  }
} catch (e) {
  console.error('Enrichment error:', e.message);
  enrichedData = {
    email: '',
    title: profile.headline || '',
    company_name: profile.company || '',
    industry: '',
    num_employees: '',
    city: '',
    state: '',
    country: '',
    website: '',
    technologies: '',
    keywords: '',
    seniority: '',
    departments: '',
    apollo_person_id: ''
  };
}

return [{
  json: {
    ...profile,
    ...enrichedData,
    enrichment_success: enrichmentSuccess
  }
}];

