// Parse AI result and map to Apollo sequence
const output = $json.output;
const lead = $('Merge Enriched Data').item.json;

let aiResult;
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  aiResult = JSON.parse(jsonMatch ? jsonMatch[0] : output);
} catch (e) {
  aiResult = { matched_service: 'Managed IT Services', reason: 'Default fallback' };
}

const serviceName = aiResult.matched_service || 'Managed IT Services';
const sequenceMap = lead.sequence_map || {};
const sequenceId = sequenceMap[serviceName] || sequenceMap['Managed IT Services'] || 'CONFIGURE_SEQUENCE_ID';

return [{
  json: {
    ...lead,
    matched_service: serviceName,
    match_reason: aiResult.reason || '',
    sequence_id: sequenceId
  }
}];

// Extract Apollo contact ID
const response = $json;
const prevData = $('Map Service to Sequence').item.json;

let contactId = '';
try {
  const body = response.body || response;
  const contact = body.contact || body;
  contactId = contact.id || '';
} catch (e) {
  console.error('Error extracting contact ID:', e.message);
}

return [{
  json: {
    ...prevData,
    apollo_contact_id: contactId
  }
}];

// Parse response and build log entry
const response = $json;
const prevData = $('Extract Contact ID').item.json;

let addedToSequence = false;
let skippedReason = '';

try {
  const body = response.body || response;
  if (body.contacts && body.contacts.length > 0) addedToSequence = true;
  if (body.skipped_contact_ids && body.skipped_contact_ids[prevData.apollo_contact_id]) {
    skippedReason = body.skipped_contact_ids[prevData.apollo_contact_id];
  }
} catch (e) { /* continue */ }

const status = addedToSequence ? 'added_to_sequence' : (skippedReason ? `skipped:${skippedReason}` : 'error');

return [{
  json: {
    profile_id: prevData.profile_id,
    full_name: prevData.full_name,
    email: prevData.email,
    company_name: prevData.company_name,
    matched_service: prevData.matched_service,
    match_reason: prevData.match_reason,
    apollo_contact_id: prevData.apollo_contact_id,
    sequence_id: prevData.sequence_id,
    status: status,
    skipped_reason: skippedReason,
    source: 'linkedin_scraper',
    enrichment_success: prevData.enrichment_success
  }
}];

// No email found - log as skipped
const lead = $('Merge Enriched Data').item.json;

console.log(`No email for ${lead.full_name} - cannot add to Apollo sequence`);

return [{
  json: {
    profile_id: lead.profile_id,
    full_name: lead.full_name,
    email: '',
    company_name: lead.company_name || lead.company,
    matched_service: 'N/A',
    match_reason: 'No email found during enrichment',
    apollo_contact_id: '',
    sequence_id: '',
    status: 'skipped:no_email',
    skipped_reason: 'no_email',
    source: 'linkedin_scraper',
    enrichment_success: false
  }
}];
